import heapq

def bellman_ford(graph, start_node, num_nodes):
    h = [float('inf')] * num_nodes
    h[start_node] = 0

    for _ in range(num_nodes - 1):
        for u in range(num_nodes):
            if h[u] == float('inf'):
                continue
            for v, weight in graph[u]:
                if h[u] + weight < h[v]:
                    h[v] = h[u] + weight

    for u in range(num_nodes):
        if h[u] == float('inf'):
            continue
        for v, weight in graph[u]:
            if h[u] + weight < h[v]:
                return None  # Negative cycle detected

    return h

def dijkstra(graph, start_node, num_nodes):
    distances = [float('inf')] * num_nodes
    distances[start_node] = 0
    priority_queue = [(0, start_node)]  # (distance, node)

    while priority_queue:
        current_dist, u = heapq.heappop(priority_queue)

        if current_dist > distances[u]:
            continue

        for v, weight in graph[u]:
            if distances[u] + weight < distances[v]:
                distances[v] = distances[u] + weight
                heapq.heappush(priority_queue, (distances[v], v))

    return distances

def johnsons_algorithm(graph, num_nodes):
    s = num_nodes 

    augmented_graph = [[] for _ in range(num_nodes + 1)]

    for i in range(num_nodes):
        augmented_graph[s].append((i, 0))

    for u in range(num_nodes):
        for v, weight in graph[u]:
            augmented_graph[u].append((v, weight))

    h = bellman_ford(augmented_graph, s, num_nodes + 1)

    if h is None:
        return "Negative cycle detected in graph."

    reweighted_graph = [[] for _ in range(num_nodes)]
    for u in range(num_nodes):
        for v, weight in graph[u]:
            reweighted_weight = weight + h[u] - h[v]
            reweighted_graph[u].append((v, reweighted_weight))

    all_pairs_shortest_paths_reweighted = []
    for u in range(num_nodes):
        all_pairs_shortest_paths_reweighted.append(dijkstra(reweighted_graph, u, num_nodes))

    final_distances = [[float('inf')] * num_nodes for _ in range(num_nodes)]
    for u in range(num_nodes):
        for v in range(num_nodes):
            if u == v:
                final_distances[u][v] = 0
            elif all_pairs_shortest_paths_reweighted[u][v] != float('inf'):
                final_distances[u][v] = (
                    all_pairs_shortest_paths_reweighted[u][v] - h[u] + h[v]
                )

    return final_distances
